function main(stream) {
  const CHAIN_ID = 97;
  const COMMUNITY    = "0x42a06ac2208e9f8e25673ba0f6c44bc56fd2aa62";
  const NODE_PRESELL = "0x6a30f26338742670637f47dfc04600b4d1ef1e9a";
  const TOPIC_REFERRER = "0x157b268685d829d4f87954a5cdff3fa1ff418e739340bfa3a2018f95702ab8ae";
  const TOPIC_PRESELL  = "0xdd5bb7eb1e6147197d4e5df191bab7769c7da72136a330645918bbd80d4d4737";

  const out = [];
  for (const entry of stream.data) {
    const receipts = Array.isArray(entry) ? entry : Object.values(entry);
    for (const r of receipts) {
      if (!r || r.status !== "0x1") continue;
      const logs = r.logs || [];
      for (const log of logs) {
        const addr = (log.address || "").toLowerCase();
        if (addr !== COMMUNITY && addr !== NODE_PRESELL) continue;
        const topic0 = (log.topics && log.topics[0] || "").toLowerCase();
        if (topic0 !== TOPIC_REFERRER && topic0 !== TOPIC_PRESELL) continue;
        out.push({
          chainId: CHAIN_ID,
          blockNumber: log.blockNumber,
          blockTimestamp: log.blockTimestamp,
          txHash: log.transactionHash,
          logIndex: log.logIndex,
          address: addr,
          topics: log.topics,
          data: log.data,
        });
      }
    }
  }
  return out.length > 0 ? out : null;
}
